var Jdump = Jdump || {};

Jdump.Tree = Jdump.Tree || {};

(function () {
	"use strict";

Jdump.Tree.imageFolder = ''; // Path to images from the Raw view default

const idOfFolderTrees = ['dhtmlgoodies_tree','dhtmlgoodies_tree2'],
	minusImage  = 'minus2.svg',
	plusImage   = 'plus.svg',
	folderImage = 'folder.svg';

Jdump.Tree.expandAll = function (treeId){

	let menuItems = document.getElementById(treeId).getElementsByTagName('li');

	for(var n=0; n<menuItems.length; n++){

		let subItems = menuItems[n].getElementsByTagName('ul');

		if(subItems.length>0 && subItems[0].style.display!='block'){
			Jdump.Tree.showHideNode(false,menuItems[n].id.replace(/[^0-9]/g,''));
		}
	}
};

Jdump.Tree.collapseAll = function (treeId){

	let menuItems = document.getElementById(treeId).getElementsByTagName('li');

	for(var n=0;n<menuItems.length;n++){

		let subItems = menuItems[n].getElementsByTagName('ul');

		if(subItems.length>0 && subItems[0].style.display=='block'){
			Jdump.Tree.showHideNode(false,menuItems[n].id.replace(/[^0-9]/g,''));
		}
	}
};

Jdump.Tree.showHideNode = function (e,inputId){

	let thisNode = null;

	if(inputId){

		if(!document.getElementById('dhtmlgoodies_treeNode'+inputId))return;

		thisNode = document.getElementById('dhtmlgoodies_treeNode'+inputId).getElementsByTagName('img')[0];
	}else {

		thisNode = this;

		if(this.tagName=='A')thisNode = this.parentNode.getElementsByTagName('img')[0];
	}

	if(thisNode.style.visibility=='hidden')return;

	let parentNode = thisNode.parentNode;
	inputId = parentNode.id.replace(/[^0-9]/g,'');

	if(thisNode.src.indexOf(plusImage)>=0){

		thisNode.src = thisNode.src.replace(plusImage,minusImage);
		let ul = parentNode.getElementsByTagName('ul')[0];
		ul.style.display='block';
	}else{

		thisNode.src = thisNode.src.replace(minusImage,plusImage);
		parentNode.getElementsByTagName('ul')[0].style.display='none';
	}

	return false;
};

Jdump.Tree.initTree = function () {

	let treeUlCounter = 0,
		nodeId = 1;

//	var contextMenuActive = false;	// Set to false if you don't want to be able to delete and add new nodes dynamically

	for(var treeCounter=0;treeCounter<idOfFolderTrees.length;treeCounter++){

		let dhtmlgoodies_tree = document.getElementById(idOfFolderTrees[treeCounter]);

		// Check if there is a tree in the view
		if (dhtmlgoodies_tree){

			let menuItems = dhtmlgoodies_tree.getElementsByTagName('li');	// Get an array of all menu items

			for(var no=0;no<menuItems.length;no++){

				nodeId++;
				let subItems = menuItems[no].getElementsByTagName('ul');
				let img = document.createElement('img');
				img.src = Jdump.Tree.imageFolder + plusImage;
				img.onclick = Jdump.Tree.showHideNode;

				if(subItems.length==0)img.style.visibility='hidden';

				else{

					subItems[0].id = 'tree_ul_' + treeUlCounter;
					treeUlCounter++;
				}

				let aTag = menuItems[no].getElementsByTagName('a')[0];

				aTag.onclick = Jdump.Tree.showHideNode;
				menuItems[no].insertBefore(img,aTag);

				if(!menuItems[no].id)menuItems[no].id = 'dhtmlgoodies_treeNode' + nodeId;

				let folderImg = document.createElement('img');

				if(menuItems[no].className){

					folderImg.src = Jdump.Tree.imageFolder + menuItems[no].className;
				}else{

					folderImg.src = Jdump.Tree.imageFolder + folderImage;
				}

				menuItems[no].insertBefore(folderImg,aTag);
			}
		} // Check end
	}
};

document.addEventListener("DOMContentLoaded", function(){
	Jdump.Tree.imageFolder = imageFolderTree;	// Path to images from the Raw view default
	Jdump.Tree.initTree();
});

})();
